function u(n){if(!n)return"n/a";let t=new Date(n);if(Number.isNaN(t.getTime()))return n;let e=t.getDate().toString().padStart(2,"0"),r=(t.getMonth()+1).toString().padStart(2,"0"),o=t.getFullYear(),i=t.getHours().toString().padStart(2,"0"),a=t.getMinutes().toString().padStart(2,"0"),s=t.getSeconds().toString().padStart(2,"0");return`${e}.${r}.${o}, ${i}:${a}:${s}`}function c(n){if(typeof n!="number"||!Number.isFinite(n)||n<0)return"n/a";let t=n/1e6;if(t<1e3)return`${t.toFixed(0)} ms`;let e=t/1e3;if(e<60)return`${e.toFixed(1)} s`;let r=Math.floor(e/60),o=e%60;return`${r}m ${o.toFixed(0)}s`}export{u as a,c as b};
